    formHelperText: maxCharacterCount ? (
      <MaxCharacterCount maxCharacterCount={maxCharacterCount} value={value} />
    ) : (
      formHelperText
    ),
    isInvalid,
    isRequired,
    label,
    name,
    testid,
    variant,
    ...formControlProps,
  };

  const conditionalInputGroupProps = {
    hasValue: !!value,
    inputGroupProps,
    inputLeftElement,
    inputRightElement,
    interactiveRightElement,
    isFocused,
    size,
    type,
    variant,
