export const ariaAttr = (condition: boolean | undefined) => (condition ? true : undefined);

export const dataAttr = (condition: boolean | undefined) => (condition ? '' : undefined);

/**
 * Assigns a value to a ref function or object
 *
 * @param ref the ref to assign to
 * @param value the value
 */
export const assignRef = (
  ref: React.MutableRefObject<unknown> | ((arg: unknown) => void),
  value: unknown
) => {
  if (ref == null) {
    return;
  }

  if (typeof ref === 'function') {
    ref(value);
    return;
  }

  try {
    // eslint-disable-next-line no-param-reassign
    ref.current = value;
  } catch (error) {
    throw new Error(`Cannot assign value '${value}' to ref '${ref}'`);
  }
};

export const callAll = (...fns: ((event: React.ChangeEvent<HTMLInputElement>) => void)[]) => {
  return (arg: React.ChangeEvent<HTMLInputElement>) => {
    fns.forEach((fn) => {
      fn?.(arg);
    });
  };
};

export const callAllHandlers = (...fns: unknown[] | ((args: unknown) => unknown)[]) => {
  return (event: unknown) => {
    fns.some((fn) => {
      (fn as (event: unknown) => void)?.(event);
      return (event as React.ChangeEvent)?.defaultPrevented;
