export const omit = (object: Record<string | symbol, unknown | string>, keys: string[]) => {
  const result: Record<string | symbol, unknown | string> = {};

  Object.keys(object).forEach((key) => {
    if (keys.includes(key)) {
      return;
    }
    result[key] = object[key];
  });

  return result;
};

